import * as React from 'react';
import { graphql, useStaticQuery } from 'gatsby';
import { getImage } from 'gatsby-plugin-image';
import Box from '@mui/material/Box';
import Layout from '../../components/layout';
import Link from '../../components/common/link';
import SectionMenu from '../../components/sections/menu';
import Thumbnails from '../../components/thumbnails';
import { Seo } from '../../components/seo';
import { works } from '../../libs/works';

const WorksPage = props => {
  const param = new URLSearchParams(props.location.search);
  const category = param.get('category');

  const worksThumbnails = useStaticQuery(graphql`
    {
      allFile(
        filter: {
          relativeDirectory: { eq: "works" }
          name: { regex: "/^.+_00$/" }
        }
      ) {
        edges {
          node {
            childImageSharp {
              gatsbyImageData(width: 400, placeholder: BLURRED)
            }
            name
          }
        }
      }
    }
  `);

  const addImageData = ({ name, category, link }) => {
    const data = worksThumbnails.allFile.edges.filter(worksThumbnail => {
      return worksThumbnail.node.name === `${name}_00`;
    });

    if (!data || !data[0] || !data[0].node) {
      console.log(name);
      console.log(data);
      return false;
    }

    const node = data[0].node;

    return {
      name,
      category,
      link,
      image: getImage(node)
    };
  };

  const datas = works.map(work => {
    return addImageData(work);
  });

  return (
    <Layout>
      <SectionMenu />
      <Box
        py={10} // header 分
      >
        <Box
          mb={4} // thumbnail の spacing 分
          sx={{
            display: 'flex',
            justifyContent: 'center'
          }}
        >
          {['All', 'Hotel', 'Interior', 'Portrait', 'Snap'].map((label, i) => {
            const _category = label.toLowerCase();

            const link = `/works/${
              _category === 'all' ? '' : `?category=${_category}`
            }`;

            const isCurrent =
              (_category === 'all' && category === null) ||
              _category === category;

            return (
              <Link
                key={i}
                href={link}
                sx={{
                  mx: {
                    md: 4,
                    sm: 2,
                    xs: 1
                  },
                  textDecoration: isCurrent && 'underline',
                  pointerEvents: isCurrent && 'none'
                }}
              >
                {label}
              </Link>
            );
          })}
        </Box>
        <Thumbnails datas={datas} category={category} />
      </Box>
    </Layout>
  );
};

export default WorksPage;

export const Head = () => {
  return <Seo title='WORKS' />;
};
